(() => {
    // 在head加载css文件
    let style = document.createElement('style');
    style.classList = "icon_loader";
    style.innerHTML = `icon{display:inline-block;width:32px;height:32px;line-height:100%}icon svg{width:100%;height:100%;fill:currentColor;stroke:currentColor}icon[name="log-out-outline"] icon[name="scan"],icon svg>*{stroke:currentColor !important}`;
    document.getElementsByTagName('head')[0].appendChild(style);
})();

// 载入zip文件
// var file = "";
var file = "data:application/x-zip-compressed;base64,";
(dataURI => {
    let mimeString = dataURI.split(',')[0].split(':')[1].split(';')[0]; // mime类型
    let byteString = atob(dataURI.split(',')[1]); //base64 解码
    let arrayBuffer = new ArrayBuffer(byteString.length); //创建缓冲数组
    let intArray = new Uint8Array(arrayBuffer); //创建视图

    for (let i = 0; i < byteString.length; i++) {
        intArray[i] = byteString.charCodeAt(i);
    }
    file = new Blob([intArray], { type: mimeString });
})(file);


var zip = new JSZip();
zip.loadAsync(file).then(zip => {
    console.debug(`debug: zip图标加载完毕`);
    function icon_loader() {
        document.querySelectorAll("icon").forEach(element => {
            // 仅渲染未渲染节点
            if (element.getAttribute('rendered') == null) {
                // 增加已渲染tag
                element.setAttribute('rendered', '');

                let svg_name;
                let full_path;
                if (element.getAttribute("name")) {
                    svg_name = element.getAttribute("name");
                    full_path = `ionicons_svg/${svg_name}.svg`;
                } else {
                    svg_name = '[Unknown Icon Name]';
                    full_path = element.getAttribute("path");
                }
                // zip文件到字符串
                try {
                    zip.files[full_path].async("string").then(data => {
                        element.innerHTML = data.replace(/<title>.*?<\/title>/gi, '');
                        console.debug(`debug: 图标加载成功: ${svg_name}　　　zip路径: ${full_path}　　　SVG标题: ${/(?<=<title>).*?(?=<\/title>)/gi.exec(data)}`);
                    });
                } catch (err) {
                    console.error(`error: 图标加载失败: ${svg_name}　　　zip路径: ${full_path}\n` + err);
                }
            }
        });
    }

    icon_loader();
    setInterval(() => {
        icon_loader();
    }, 10 * 1000);

});